<template>
  <div class="user">
    <div class="user_read">
      <div 
        v-for="(item,index ) of readContent"
        :key="index"
        class="line"
      >
        <div class="line_title">
          <div class="line_pic">
            <img :src="item.users.user_img">
          </div>
          <div class="user_name">
            {{ item.users.userName }}
          </div>
        </div>
        <span class="lines_said">{{ item.content }}</span>
        <span class="time">发布于:{{ item.create_time }}</span>
      </div>
    </div>
    <div class="user_write">
      <textarea
        class="content"
        v-model.trim="content"
        placeholder="请留言!"
      />
      <span 
        class="content_send"
        @click="comment"
      > 发布</span>
    </div>
  </div>
</template>
<script>
import api from "../../api/singleshop/api.js";
export default {
    data (){
        return {
            // 评论内容
            content:"",
            // 获取用户留言
            readContent:""

        };

    },
    beforeRouteEnter(to,from,next){
        next(vm => {
            document.documentElement.scrollTop = vm.$store.state.scrollTop;
        });

    },
    beforeRouteLeave (to, from, next) {
        let scrollTop = document.documentElement.scrollTop;
        this.setScrollTop(scrollTop);
        next();
    },
    created (){
        this.read();

    },
    methods:{
        // 设置商品详情页的scrolltop
        setScrollTop(pos){
            this.$store.commit("setScrollTop",pos);
        },
        // 留言
        comment (){
            this.axios.post(api.write,{
                // 评论内容
                content:this.content,
                // 商品的id
                goodsId: this.$route.params.currentElementId
            }).then(response => {
                if(response.code === 200){
                    this.content = "";
                    this.read();
                }
                return;
            }).catch(error => {
                console.log(error);
            });
        },
        // 获取用户留言
        read (){
            const writePid = this.$route.params.currentElementId;
            this.axios.get(`${api.read}/${writePid}`).then(response => {
                if(response.code === 200){
                    this.readContent = response.data;

                }
                return ;
            }).catch(error => {
                console.log(error);
            });
        }

    }
};
</script>
<style lang="scss" scoped>
.user{
    position:relative;
    .user_read{
        .line{
            width:100%;
            height:90px;
            border-bottom: 1px solid black;
            overflow:hidden;
            margin-top:20px;
            position:relative;
            .line_title{
                display:inline-flex;
                flex-direction: column;
                align-items: center;
                border-radius:5%;
                width:70px;
                height:100%;
                background-color:darkgray;
                .line_pic{
                    height:60%;
                    width:80%;
                    border-radius:50%;
                    overflow:hidden;
                    img{
                        width:100%;
                        height:100%;
                    }
                }
                .user_name{
                    margin-top:10px;
                    width:80%;
                    
                }
            }
            .lines_said{
                margin-left:100px;
            }
            .time{
                position:absolute;
                right:20px;
                bottom:10px;

            }
        }
    }
    .user_write{
        margin-top:400px;
        .content{
            width:900px;
            height:100px;
            resize:none;
            
        }
        .content_send{
            float:right;
            margin-right:100px;
            padding:10px 15px;
            background-color:blue;
            border-radius:4px;
            cursor: pointer;
        }
    }

}

</style>