<template>
  <div> 
    <my-header 
      :user="user" 
      :orders="orders"
      @clearUser="clearUser"
    />
    <div class="container">
      <div class="logo">
        <img src="../images/logo.png">
      </div>
      <div class="list_pic_show">
        <div class="list">
          <div class="list_title">
            全部分类
          </div>
          <div 
            v-for="(item,index) of foodlistsort"
            :key="index"
            class="list_item"
            :data-index="index"
            @mouseenter="showStatus"
            @mouseleave="hiddenStatus"
          >
            <div
              class="list_item_detail"
            >
              <a 
                href="#"
                class="title"
              >{{ item.foot_name }}
              </a>
            </div>
            <div
              v-for="(list,i) of item.children"
              :key="i"
              v-show="i < 2"
              class="list_item_detail"
            >
              <a 
                href="#"
                class="title"
                :data-id="list.id"
                @click.stop="toList"
              >{{ list.foot_name }}</a>
            </div>
              
            <div 
              class="list_detail_hot_sort"
              v-show="index ==currentIndex"
              @mouseleave="itemList = null"
            >
              <div 
                v-for="(hotSortItem,j) of item.children"
                :key="j"
                v-show="j >= 2"
                @mouseenter.stop="getItemList(hotSortItem.id)"
                class="line-item"
              >
                <div 
                  class="hot_title"
                  :data-id="hotSortItem.id"
                  @click.stop="toList($event)"
                >
                  {{ hotSortItem.foot_name }}
                </div>
                <span
                  v-for="(item,k) of itemList"
                  :key="k"
                  class="item_title"
                  :class="{'border_clear':k%4 === 0 }"
                >
                  <a
                    href="#"
                    :data-id="item.id"
                    :data-pid="item.pid"
                    @click.stop="onDetail($event)"
                    class="item_point"
                  > {{ item.foot_name }}</a></span>
              </div>
            </div>
          </div>
        </div>
        <my-slider />
      </div>
    </div>
    <my-floor :list="list" />
    <my-footer />
  </div>
</template>
<script>
import mySlider from "./slider.vue";
import api from "../api/index/api.js";
import myHeader from "./header.vue";
import myFooter from "../commen/components/footer.vue";
import myFloor from "./floor.vue";
export default {
    name:"Index",
    data (){
        return {
            // 默认为不显示更多分类数据,id小于0即可
            currentIndex:-1,
            // 商品全部分类数据
            foodlistsort:"",
            // 分类下的全部商品
            itemList:[],
            logoImgSrc:"../images/logo.png",
            // 用户信息
            user:{},
            // 用户订单数
            orders:0,
            // 楼层列表数据
            list :[]

        };
    },
    created (){

        this.getFoodListSort();
        this.getUser();
        this.getUserOrders();
        this.getFoodList();

    },
    methods:{

        // 获取用户信息
        getUser (){
            this.axios.get(`${api.user}`).then(response => {
                if(response.code === 200){
                    this.user = response.data;
                }
                return;
            }).catch(error => {
                console.log(error);
            });

        },
        // 获取用户订单数
        getUserOrders (){
            this.axios.get(api.orders).then(response => {
                if(response.code === 200){

                    this.orders = response.data.order_num;
                }
                return;
            }).catch(error => {
                console.log(error);
            });
        },
        // 用户推出
        clearUser (){
            this.user = { };
            this.orders = 0;

        },
        // 前往分类下的全部商品的展示页
        toList (event){
            let currentElementId = event.target.dataset.id;
            this.$router.push({
                path:`/list/${currentElementId}`,
            });

        },
        // 前往商品详情页
        onDetail (event){
            const currentElementId = event.target.dataset.id,
                currentElementPid = event.target.dataset.pid;

            this.$router.push({
                path:`/productionDetail/${currentElementPid}/${currentElementId}`,
            });

        },

        // 获取楼层列表数据
        getFoodList (){
            this.axios.get(`${api.floorList}`).then(response => {
                if(response.code === 200){
                    this.list = response.data;

                }
                
                return;
            }).catch(error => {
                console.log(error);
            });
        },
        /**
         *  获取商品全部分类
         */
        getFoodListSort(){
            this.axios.get(api.listSort).then(response => {
                if(response.code === 200){
                    this.foodlistsort = response.data;
                }
                
                return;
            }).catch(error => {
                console.log(error);
            });

        },
        // 显示更多分类数据
        showStatus (event){
            this.currentIndex = event.target.dataset.index;
        },
        // 隐藏更多分类数据
        hiddenStatus(){
            this.currentIndex = -1;
        },
    
        // 获取分类下的全部商品
        getItemList(id){
            this.axios.get(`${api.itemList}/${id}`).then(response => {
                if(response.code === 200){
                    this.itemList = response.data;
                }
                return null;
            }).catch(error => {
                console.log(error);
            });
        }
    },
    components:{
        mySlider,
        myHeader,
        myFloor,
        myFooter,
    }
    
};
</script>
<style lang="scss" scoped>
.container{
    width:1200px;
    margin:0 auto;
    .logo{
        margin-top:25px;
        width:226px;
        height:40px;
        overflow:hidden;
    }
    .list_pic_show{
        margin-top:20px;
        position:relative;
        .list{
            width:226px;
            position:relative;
            .list_title{
                color:white;
                font-size:19px;
                height:40px;
                line-height:40px;
                padding-left:20px;
                background-color:rgb(228,0,127);
            }
            .list_item{
                padding:0 15px;
                height:48px;
                border-left:1px solid rgb(201,201,201);
                border-bottom:1px solid rgb(201,201,201);
                background-color:whitesmoke;
                position:relative;
                .list_item_detail{
                    height:100%;
                    float:left;
                    line-height:48px;
                }
                .list_item_detail:first-child {
                    padding-right:20px;
                     .title{
                        color:black;
                        font-weight: 500;
                        &:hover{
                        color:rgb(228,0,127)
                    }
                    }
                    
                }
                .list_item_detail:not(:first-child){
                    font-size:13px;
                    margin-left:15px;
                    .title{
                        &:hover{
                            color:rgb(0,104,183);
                            text-decoration: underline;
                        }
                    }
                    
                }
                .list_detail_hot_sort{
                    position:absolute;
                    z-index:9999;
                    top:0;
                    left:225px;
                    width:410px;
                    border:1px solid rgb(201,201,201);
                    background-color:white;
                    .line-item{
                        padding:10px 15px;
                        border-bottom:1px solid rgb(201,201,201);
                        &:last-child{
                            border:none;
                        }
                    }
                    .hot_title{
                        font-size:12px;
                        font-weight:bold;
                        padding-left:15px;
                        color:rgb(98,98,98);
                        cursor: pointer;
                        &:hover{
                            color:rgb(0,117,169);
                            text-decoration:underline;
                        }
                    }
                    .item_title{
                        height:20px;
                        width:80px;
                        padding-left:10px;
                        display: inline-block;
                        line-height:20px;
                        font-size:13px;
                        font-weight:400;
                        overflow:hidden;
                        color:rgb(201,201,201);
                        border-left:1px solid rgb(201,201,201);
                        .item_point{
                            &:hover{
                                color:rgb(0,117,169);
                                text-decoration:underline;
                            }
                        }
                        
                    }
                    .border_clear{
                        border:none;
                    }
                }

            }

        }

    }
}

</style>


